sys_ui_action.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
var now = new GlideDateTime();
// STRY0072379
var bDateOk = true;

// STRY0072379
if(gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future') == 'true'){
	if(now > current.suspense_date && current.suspense_date != ""){
		gs.addErrorMessage('The suspense date must be in the future.');
		bDateOk = false;
	}
}

if (bDateOk){
	if(current.assigned_to.nil() || current.primary_assignee.nil()) {
		// 		gs.addErrorMessage(gs.getMessage(current.number + ': Task was assigned to an OU but not to an Assignee'));
		var assignee = current.primary_assignee.getDisplayValue();
		current.state = -5;
		current.work_notes = "Assigned to " + assignee;
		current.update();
		//gs.addInfoMessage(current.number + ' has been assigned to ' + assignee);
		action.setRedirectURL(current);
	} else{
		var assigned_to = current.assigned_to.getDisplayValue();
		current.state = 1;
		current.work_notes = "Assigned to " + assigned_to;
		current.update();
		//gs.addInfoMessage(current.number + ' has been assigned to ' + assigned_to);
		action.setRedirectURL(current);
	}
}
